// Initialize battery level and state (on first run or retrieved from context)
let batteryLevel = context.get('batteryLevel');
if (batteryLevel === undefined) {
    batteryLevel = 0;  // Start at 0 on the first run
}

let decreasing = context.get('decreasing');
if (decreasing === undefined) {
    decreasing = false;  // Default to charging mode if battery is low at the start
}

// Simulate the battery charging/discharging based on the current level
if (batteryLevel < 80) {
    // 80% chance to charge if battery level is below 80%
    if (Math.random() < 0.8) {
        decreasing = false;  // Charging mode
    } else {
        decreasing = true;  // Discharge mode (20% chance)
    }
} else {
    // Above 80%, prioritize discharging
    decreasing = true;
}

// Simulate the battery consumption and charging process
if (decreasing) {
    // Decrease battery level by a random value between 0 and 1
    let randomDecrease = Math.random();  // Random decrease between 0 and 1
    batteryLevel -= randomDecrease;

    // Ensure battery level doesn't go below 0
    if (batteryLevel <= 0) {
        batteryLevel = 0;
        decreasing = false;  // Switch to charging mode once the battery is depleted
    }
} else {
    // Gradually charge the battery by a random value between 1 and 3 points
    let chargeIncrease = Math.random() * (3 - 1) + 1;  // Random increase between 1 and 3
    batteryLevel = Math.min(100, batteryLevel + chargeIncrease);  // Ensure it doesn't go over 100

    // If the battery reaches full capacity, start discharging
    if (batteryLevel >= 100) {
        batteryLevel = 100;
        decreasing = true;  // Start discharging once the battery is full
    }
}

// Determine battery status based on the battery level
let out = {};
if (batteryLevel < 20) {
    out.batteryStatus = "Low";
} else if (batteryLevel >= 20 && batteryLevel <= 99) {
    out.batteryStatus = "Normal";
} else {
    out.batteryStatus = "Full";
}

// Simulate charging status (whether charging is occurring or not)
let isCharging = !decreasing;  // Charging when not decreasing

// Create an output object to store the battery level, status, and charging state
out.batteryLevel = batteryLevel.toFixed(2);  // Keep 2 decimal places
out.batteryChargingStatus = isCharging ? "Charging" : "Not charging";  // Display "Charging" or "Not charging"

// Save updated battery level and state to context
context.set('batteryLevel', batteryLevel);
context.set('decreasing', decreasing);

// Output the current battery level, status, and charging state as JSON
msg.payload = out;
return msg;

