// Initialize water level and state (on first run or retrieved from context)
let waterLevel = context.get('waterLevel');
if (waterLevel === undefined) {
    waterLevel = 0;  // Start at 0 on the first run
}

let decreasing = context.get('decreasing');
if (decreasing === undefined) {
    decreasing = false;  // Start by refilling if water level is 0 initially
}

// Simulate the water consumption and refill process
if (decreasing) {
    // Decrease water level by a random value between 0 and 10
    let randomDecrease = Math.floor(Math.random() * 11);  // 0 to 15 inclusive
    waterLevel -= randomDecrease;

    // Ensure water level doesn't go below 0
    if (waterLevel <= 0) {
        waterLevel = 0;
        decreasing = false;  // Switch to refill mode
    }
} else {
    // During the refill phase, sometimes decreasing can also happen (30% chance)
    let randomAction = Math.random(); // Generate a random number between 0 and 1

    if (randomAction < 0.3) {  // 30% chance to decrease during refill phase
        let randomDecrease = Math.floor(Math.random() * 16);  // 0 to 15 inclusive
        waterLevel -= randomDecrease;

        // Ensure water level doesn't go below 0
        if (waterLevel < 0) {
            waterLevel = 0;
        }
    } else {
        // Gradually refill the water by 5 units at a time
        waterLevel += 20;

        // Ensure water level doesn't exceed 100
        if (waterLevel >= 100) {
            waterLevel = 100;
            decreasing = true;  // Switch back to decreasing mode once full
        }
    }
}

// Save updated water level and state to context
context.set('waterLevel', waterLevel);
context.set('decreasing', decreasing);

// Output the current water level as JSON
msg.payload = { "Water_Level(%)": waterLevel };
return msg;
